sql:
SELECT s.section_name
FROM sections s
WHERE s.section_id IN (SELECT tr.section_id FROM test_results tr);

external_knowledge:
- 'High Pass Rate' refers to a pass rate of 60% or above;
- 'Medium Pass Rate' refers to a pass rate between 40% and 59%;
- 'Low Pass Rate' refers to a pass rate below 40%;
- The category 'Low Average Failed Cases' is for sections with an average of 3 or fewer failed cases;
- 'Medium Average Failed Cases' is for sections with an average between 4 and 6 failed cases;
- 'High Average Failed Cases' is for sections with more than 6 average failed cases.

sql:
SELECT access_type
FROM access_logs
WHERE user_id = 1 AND access_id = 1;

SELECT users.user_name, test_runs.environment
FROM test_runs
JOIN users ON test_runs.user_id = users.user_id;

SELECT tr.result_id, tr.section_id, tr.total_cases, tr.failed, tr.passed, trn.user_id
FROM test_results tr
JOIN test_runs trn ON tr.test_run_id = trn.run_id;

SELECT * FROM sections
WHERE section_id = 1
ORDER BY section_name ASC;
